# test_deep_get.py
import pytest

# Import the function to test – adjust the import path as needed.
# from mymodule import deep_get
def deep_get(d: dict, keys: str, default=None):
    """Get nested dict value by dot‑separated keys."""
    for key in keys.split('.'):
        if isinstance(d, dict):
            d = d.get(key, default)
        else:
            return default
    return d


# ----------------------------------------------------------------------
# Helper data structures used across multiple tests
# ----------------------------------------------------------------------
SIMPLE = {"a": 1, "b": 2}
NESTED = {
    "user": {
        "profile": {
            "name": "Alice",
            "age": 30,
            "address": {
                "city": "Wonderland",
                "zip": "12345"
            }
        },
        "preferences": {
            "theme": "dark",
            "notifications": True
        }
    },
    "meta": {
        "version": "1.0.0",
        "tags": ["alpha", "beta"]
    }
}


# ----------------------------------------------------------------------
# Happy‑path tests
