@pytest.mark.parametrize(
    "data, keys, expected",
    [
        # Top‑level key
        (SIMPLE, "a", 1),
        (SIMPLE, "b", 2),

        # One level deep
        (NESTED, "user.profile.name", "Alice"),
        (NESTED, "user.profile.age", 30),

        # Two levels deep
        (NESTED, "user.profile.address.city", "Wonderland"),
        (NESTED, "user.profile.address.zip", "12345"),

        # Mixed types (list inside dict – we only traverse dicts)
        (NESTED, "meta.tags", ["alpha", "beta"]),

        # Boolean value
        (NESTED, "user.preferences.notifications", True),

        # String value
        (NESTED, "meta.version", "1.0.0"),
    ],
)
def test_deep_get_happy_path(data, keys, expected):
    assert deep_get(data, keys) == expected


