def test_deep_get_empty_keys_string():
    """An empty string splits to ['']; we look for the literal key ''."""
    d = {"": 42, "a": 1}
    assert deep_get(d, "") == 42          # key '' exists
    assert deep_get({"a": 1}, "") is None # key '' missing → default None


def test_deep_get_leading_trailing_dot():
    """Leading/trailing dots produce empty string components."""
    d = {"a": {"b": 5}}
    # ".a.b" → ['', 'a', 'b']; first '' is not in dict → default
    assert deep_get(d, ".a.b") is None
    # "a.b." → ['a', 'b', '']; last '' not in dict → default
    assert deep_get(d, "a.b.") is None
    # If we actually store the empty‑string key, it works
    d2 = {"": {"a": {"b": 5}}}
    assert deep_get(d2, ".a.b") == 5   # ['', 'a', 'b'] → found


